// Filtrar equipos que vencen mañana y hoy
const today = new Date();
today.setHours(0, 0, 0, 0);
const tomorrow = new Date(today);
tomorrow.setDate(tomorrow.getDate() + 1);
const dayAfter = new Date(today);
dayAfter.setDate(dayAfter.getDate() + 2);

const formatDate = (date) => date.toISOString().split('T')[0];

const equipment = $input.all().map(item => item.json);

// Filtrar por fechas
const expiringTomorrow = equipment.filter(e => {
  if (!e.fecha_fin_renta) return false;
  const rentaFin = new Date(e.fecha_fin_renta);
  rentaFin.setHours(0, 0, 0, 0);
  return rentaFin.getTime() === tomorrow.getTime();
});

const expiringToday = equipment.filter(e => {
  if (!e.fecha_fin_renta) return false;
  const rentaFin = new Date(e.fecha_fin_renta);
  rentaFin.setHours(0, 0, 0, 0);
  return rentaFin.getTime() === today.getTime();
});

return [
  { json: { type: 'tomorrow', count: expiringTomorrow.length, equipment: expiringTomorrow } },
  { json: { type: 'today', count: expiringToday.length, equipment: expiringToday } }
];

// Procesar equipos que vencen mañana
const data = $input.first().json;
const equipment = data.equipment;

if (!equipment || equipment.length === 0) {
  return [{ json: { alerts_created: 0, alerts: [] } }];
}

const alerts = equipment.map(item => ({
  user_id: item.user_id,
  tipo_alerta: 'renta_vence_manana',
  referencia_id: item.id,
  fecha_ejecucion: new Date().toISOString().split('T')[0],
  nombre: item.nombre,
  proveedor: item.proveedor_renta,
  fecha_fin: item.fecha_fin_renta,
  message: `⚠️ El equipo

 rentado a ${item.proveedor_renta} vence MAÑANA (${item.fecha_fin_renta}). Recuerda preparar la devolución.`
}));

return [{ json: { alerts_created: alerts.length, alerts: alerts } }];

// Procesar equipos que vencen HOY
const data = $input.first().json;
const equipment = data.equipment;

if (!equipment || equipment.length === 0) {
  return [{ json: { alerts_created: 0, alerts: [] } }];
}

const alerts = equipment.map(item => ({
  user_id: item.user_id,
  tipo_alerta: 'renta_vence_hoy',
  referencia_id: item.id,
  fecha_ejecucion: new Date().toISOString().split('T')[0],
  nombre: item.nombre,
  proveedor: item.proveedor_renta,
  fecha_fin: item.fecha_fin_renta,
  message: `🚨 URGENTE: El equipo

 rentado a ${item.proveedor_renta} vence HOY. Debe devolverse hoy.`
}));

return [{ json: { alerts_created: alerts.length, alerts: alerts } }];

// Combinar alertas de ambos flujos
const tomorrowData = $node["Procesar Vencen Mañana"].json;
const todayData = $node["Procesar Vencen Hoy"].json;

const allAlerts = [
  ...(tomorrowData.alerts || []),
  ...(todayData.alerts || [])
];

if (allAlerts.length === 0) {
  return [{ json: { has_alerts: false, message: 'No hay alertas hoy' } }];
}

// Preparar mensaje para Telegram
let telegramMessage = `🔔 **Alertas de Equipo Rentado**\n`;
telegramMessage += `📅 ${new Date().toLocaleDateString('es-MX')}\n\n`;

if (tomorrowData.alerts && tomorrowData.alerts.length > 0) {
  telegramMessage += `⏳ **Vencen MAÑANA (${tomorrowData.alerts.length}):**\n`;
  tomorrowData.alerts.forEach(a => {
    telegramMessage += `• ${a.nombre} - ${a.proveedor}\n`;
  });
  telegramMessage += '\n';
}

if (todayData.alerts && todayData.alerts.length > 0) {
  telegramMessage += `🚨 **Vencen HOY (${todayData.alerts.length}):**\n`;
  todayData.alerts.forEach(a => {
    telegramMessage += `• ${a.nombre} - ${a.proveedor}\n`;
  });
}

return [{
  json: {
    has_alerts: true,
    telegram_message: telegramMessage,
    total_alerts: allAlerts.length,
    tomorrow_count: tomorrowData.alerts?.length || 0,
    today_count: todayData.alerts?.length || 0,
    alerts: allAlerts
  }
}];
